def gen(rng, size):
    n = rng.randint(1, max(1, min(size, 40)))
    vals = [rng.randint(-20, 20) for _ in range(n)]
    tree = [vals[0]]
    i = 1
    pos = 0
    while pos < len(tree) and i < n:
        if tree[pos] is not None:
            for _ in range(2):
                if i < n and rng.random() < 0.8:
                    tree.append(vals[i]); i += 1
                else:
                    tree.append(None)
        else:
            tree.append(None)
            tree.append(None)
        pos += 1
    while tree and tree[-1] is None:
        tree.pop()
    limit = rng.randint(-30, 60)
    return [tree, limit]

