class Solution:
    def sufficientSubset(self, root, limit):
        def collect(node, acc, path, keep):
            if node is None:
                return
            path.append(node)
            if node.left is None and node.right is None:
                if acc + node.val >= limit:
                    for p in path:
                        keep.add(id(p))
            else:
                collect(node.left, acc + node.val, path, keep)
                collect(node.right, acc + node.val, path, keep)
            path.pop()
        keep = set()
        collect(root, 0, [], keep)
        def rebuild(node):
            if node is None or id(node) not in keep:
                return None
            node.left = rebuild(node.left)
            node.right = rebuild(node.right)
            return node
        return rebuild(root)

