class Solution:
    def sufficientSubset(self, root, limit):
        def dfs(node, rem):
            if node is None:
                return None
            if node.left is None and node.right is None:
                return None if node.val < rem else node
            node.left = dfs(node.left, rem - node.val)
            node.right = dfs(node.right, rem - node.val)
            if node.left is None and node.right is None:
                return None
            return node
        return dfs(root, limit)

